import java.util.Scanner;

public class SecureBufferHandling {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Fixed code to prevent buffer overflow
        char[] buffer = new char[10];
        int length = Math.min(userInput.length(), buffer.length); // Limit input length to buffer size
        userInput.getChars(0, length, buffer, 0);

        System.out.println("Buffer overflow vulnerability successfully mitigated!");
    }
}

